#include<bits/stdc++.h>
using namespace std;
#define ll long long int
#define ld long double
vector < ll > primes;
vector < bool > is_prime;
void sieve(ll n) {
    is_prime.assign(n + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (ll i = 2; i * i <= n; i++) {
        if (is_prime[i]) {
            for (ll j = i * i; j <= n; j += i) is_prime[j] = false;
        }
    }
    for (ll i = 2; i <= n; i++) {
        if (is_prime[i]) primes.push_back(i);
    }
}
vector < ll > prime_factor(ll n) {
    vector < ll > ret;
    for (ll p: primes) {
        if (p * p > n) break;
        while (n % p == 0) {
            ret.push_back(p);
            n /= p;
        }
    }
    if (n > 1) ret.push_back(n);
    return ret;
}
bool isprime_check(ll num) {
    for (ll i = 2; i <= sqrt(num); i++) {
        if (num % i == 0) {
            return false;
        }
    }
    return true;
}
ll countDivisors(ll num) {
    ll cnt = 0;
    for (ll i = 1; i * i <= num; i++) {
        if (num % i == 0) {
            if (i * i == num) cnt++;
            else cnt += 2;
        }
    }
    return cnt;
}
