const ll N = 200000;
const ll MOD = 1e9+7; // change this value
ll fact[N], invfact[N];
ll binpow(ll a,ll b) {
    ll res = 1;
    while (b > 0) {
        if (b & 1) res = res * a % MOD;
        a = a * a % MOD;
        b >>= 1;
    }
    return res;
}
void precompute() {
    fact[0] = 1;
    for (ll i = 1; i < N; i++)
        fact[i] = fact[i-1] * i % MOD;

    invfact[N-1] = binpow(fact[N-1], MOD-2);
    for (ll i = N-2; i >= 0; i--)
        invfact[i] = invfact[i+1] * (i+1) % MOD;
}

ll nCr(ll n, ll r) {
    if (r < 0 || r > n) return (0LL);
    return fact[n] * invfact[r] % MOD * invfact[n-r] % MOD;
}
