ll mex(vector < ll > mm) {
    map < ll, ll > mmm;
    for (auto it: mm) {
        mmm[it]++;
    }
    for (ll i = 0; i <= mm.size(); i++) {
        if (mmm.find(i) == mmm.end()) {
            return i;
        }
    }
    ll mmmm = mm.size();
    return mmmm;
}
ll find_xor(ll n) {
    if (n % 4 == 0) return n;
    if (n % 4 == 1) return 1;
    if (n % 4 == 2) return n + 1;
    return 0;
}
ll _gcd(ll a, ll b) {
    if (b == 0) return a;
    else return _gcd(b, a % b);
}
ll _lcm(ll a, ll b) {
    return ((a) / (_gcd(a, b)) * b);
